package com.careeros.validation.application;import org.springframework.stereotype.Service;import java.util.*;import java.util.regex.*;@Service public class ResumeGroundingValidator{private static final Set<String>TECH=Set.of("java","spring","spring boot","kafka","aws","azure","gcp","kubernetes","docker","terraform","postgresql","mysql","mongodb","redis","python","javascript","typescript","react","angular","node","go","rust","scala","spark","datadog","grafana","jenkins","github","gitlab");private static final Pattern METRIC=Pattern.compile("(?i)(?:[$€£]?\\d+(?:[.,]\\d+)?%?|\\d+[xX])");public Result validate(String master,List<String>bullets){String source=normalize(master),generated=normalize(String.join(" ",bullets));List<String>w=new ArrayList<>();for(String t:TECH)if(contains(generated,t)&&!contains(source,t))w.add("Unknown technology: "+t);Matcher m=METRIC.matcher(String.join(" ",bullets));while(m.find())if(!master.contains(m.group()))w.add("Unknown metric: "+m.group());return new Result(w.isEmpty(),w.stream().distinct().toList());}private boolean contains(String text,String term){return(" "+text+" ").contains(" "+term+" ");}private String normalize(String x){return x.toLowerCase(Locale.ROOT).replaceAll("[^a-z0-9+#.]+"," ").trim();}public record Result(boolean valid,List<String>warnings){} }
